+body {
+    margin: 0;
+    padding: 0;
+    font-family: 'Pretendard', sans-serif;
+    background-color: #f8f9fa;
+    display: flex;
+    justify-content: center;
+    align-items: center;
+    height: 100vh;
+    user-select: none;
+    touch-action: manipulation; /* 모바일 더블탭 줌 방지 */
+}
+
+#game-wrapper {
+    background: white;
+    padding: 20px;
+    border-radius: 20px;
+    box-shadow: 0 10px 30px rgba(0,0,0,0.1);
+    text-align: center;
+    width: 320px;
+    position: relative;
+}
+
+h2 { margin-top: 0; margin-bottom: 10px; color: #333; font-size: 20px; }
+p { color: #666; font-size: 14px; margin-bottom: 15px; line-height: 1.4; }
+
+.status-board {
+    display: flex;
+    justify-content: space-between;
+    background: #f1f3f5;
+    padding: 10px 15px;
+    border-radius: 10px;
+    margin-bottom: 15px;
+    font-weight: bold;
+    font-size: 14px;
+}
+
+.time { color: #ff6b6b; }
+.score { color: #20c997; }
+
+/* 🃏 카드 그리드 (가로 4칸, 세로 3칸) */
+#card-grid {
+    display: grid;
+    grid-template-columns: repeat(4, 1fr);
+    gap: 10px;
+    perspective: 1000px; /* 3D 효과 원근감 */
+    margin-bottom: 10px;
+}
+
+/* 개별 카드 */
+.card {
+    width: 100%;
+    aspect-ratio: 3 / 4; /* 카드 비율 (세로로 약간 길게) */
+    position: relative;
+    transform-style: preserve-3d;
+    transition: transform 0.4s ease-in-out;
+    cursor: pointer;
+}
+
+/* 카드가 뒤집혔을 때 클래스 */
+.card.flip {
+    transform: rotateY(180deg);
+}
+
+.card-front, .card-back {
+    position: absolute;
+    width: 100%;
+    height: 100%;
+    backface-visibility: hidden; /* 뒷면일 때 안 보이게 처리 */
+    display: flex;
+    justify-content: center;
+    align-items: center;
+    border-radius: 8px;
+    box-shadow: 0 4px 8px rgba(0,0,0,0.1);
+    font-size: 32px; /* 이모지 크기 */
