+++ b/server/core/game_rules.py
@@ -0,0 +1,86 @@
+from __future__ import annotations
+
+from core.special_tiles import get_special_zone_info, parse_grid_id
+
+BASIC_GAME_TYPES = ["basic_tap", "basic_rps", "basic_timing"]
+
+
+def _basic_seed_from_grid(grid_id: str) -> int:
+    point = parse_grid_id(grid_id)
+    if point:
+        return abs(point.row * 17 + point.col * 31)
+
+    seed = 0
+    for ch in grid_id:
+        seed = (seed * 31 + ord(ch)) & 0xFFFFFFFF
+    return seed
+
+
+def choose_basic_game_type(grid_id: str) -> str:
+    seed = _basic_seed_from_grid(grid_id)
+    return BASIC_GAME_TYPES[seed % len(BASIC_GAME_TYPES)]
+
+
+def _special_rules_by_type(special_type: str) -> tuple[int, dict]:
+    if special_type == "5x5":
+        return (
+            3,
+            {
+                "boss_hp": 300,
+                "damage_per_hit": 1,
+                "click_limit_per_user": 40,
+                "required_teamplay": True,
+            },
+        )
+
+    return (
+        2,
+        {
+            "boss_hp": 120,
+            "damage_per_hit": 1,
+            "click_limit_per_user": 20,
+            "required_teamplay": True,
+        },
+    )
+
+
+def get_game_config_for_tile(grid_id: str) -> dict:
+    zone = get_special_zone_info(grid_id)
+    in_special_zone = bool(zone["in_special_zone"])
+    special_type = zone["special_zone_type"]
+    special_center_grid_id = zone["special_center_grid_id"] or grid_id
+    is_special_center = bool(zone["is_special_center"])
+
+    if in_special_zone and special_type:
+        level, rules = _special_rules_by_type(special_type)
+        return {
+            "grid_id": grid_id,
+            "mode": "special",
+            "pattern": (
+                f"special_{special_type}_center"
+                if is_special_center
+                else f"special_{special_type}_zone"
+            ),
+            "special_type": special_type,
+            "game_type": "boss_click",
+            "title": f"Special Boss Tile ({special_type})",
+            "level": level,
+            "rules": rules,
+            # Non-center tiles in the same special zone share one boss state.
+            "boss_grid_id": special_center_grid_id,
+            "is_special_center": is_special_center,
+        }
+
+    game_type = choose_basic_game_type(grid_id)
+    return {
+        "grid_id": grid_id,
+        "mode": "basic",
+        "pattern": None,
+        "special_type": None,
+        "game_type": game_type,
+        "title": "Basic Tile Mini Game",
+        "level": 1,
+        "rules": {
+            "target_success": True,
+        },
+    }
diff --git a/server/core/game_runtime.py b/server/core/game_runtime.py
new file mode 100644
index 0000000..c73cea9
--- /dev/null
+++ b/server/core/game_runtime.py
@@ -0,0 +1,208 @@
+from __future__ import annotations
+
+import uuid
+from dataclasses import dataclass, asdict
+from datetime import datetime, timedelta, timezone
+from threading import Lock
+
+SESSION_TTL_MINUTES = 10
+
+
+@dataclass
+class GameSession:
+    session_id: str
+    grid_id: str
+    boss_grid_id: str | None
+    game_type: str
+    mode: str
+    user_key: str
+    status: str
+    score: int
+    game_level: int
+    created_at: datetime
+    expires_at: datetime
+
+    def to_dict(self) -> dict:
+        data = asdict(self)
+        data["created_at"] = self.created_at.isoformat()
+        data["expires_at"] = self.expires_at.isoformat()
+        return data
+
+
+@dataclass
+class BossState:
+    grid_id: str
+    max_hp: int
+    current_hp: int
+    damage_per_hit: int
+    click_limit_per_user: int
+    updated_at: datetime
+
+    def to_dict(self) -> dict:
+        return {
+            "grid_id": self.grid_id,
+            "max_hp": self.max_hp,
+            "current_hp": self.current_hp,
+            "damage_per_hit": self.damage_per_hit,
+            "click_limit_per_user": self.click_limit_per_user,
+            "updated_at": self.updated_at.isoformat(),
+        }
+
+
+_sessions: dict[str, GameSession] = {}
+_boss_states: dict[str, BossState] = {}
+_user_clicks: dict[tuple[str, str], int] = {}
+_runtime_lock = Lock()
+
+
+def _now() -> datetime:
+    return datetime.now(timezone.utc)
+
+
+def _purge_expired_sessions() -> None:
+    now = _now()
+    expired_ids = [sid for sid, session in _sessions.items() if session.expires_at <= now]
+    for sid in expired_ids:
+        session = _sessions.pop(sid, None)
+        if not session:
+            continue
+        boss_key = session.boss_grid_id or session.grid_id
+        _user_clicks.pop((boss_key, session.user_key), None)
+
+
+def create_session(grid_id: str, game_config: dict, user_key: str) -> GameSession:
+    with _runtime_lock:
+        _purge_expired_sessions()
+
+        now = _now()
+        session = GameSession(
+            session_id=str(uuid.uuid4()),
+            grid_id=grid_id,
+            boss_grid_id=game_config.get("boss_grid_id"),
+            game_type=game_config["game_type"],
+            mode=game_config["mode"],
+            user_key=user_key,
+            status="READY",
+            score=0,
+            game_level=int(game_config["level"]),
+            created_at=now,
+            expires_at=now + timedelta(minutes=SESSION_TTL_MINUTES),
+        )
+        _sessions[session.session_id] = session
+        return session
+
+
+def get_session(session_id: str) -> GameSession | None:
+    with _runtime_lock:
+        _purge_expired_sessions()
+        return _sessions.get(session_id)
+
+
+def submit_basic_result(
+    session_id: str,
+    success: bool,
+    score: int,
+    game_level: int,
+) -> GameSession | None:
+    with _runtime_lock:
+        _purge_expired_sessions()
+        session = _sessions.get(session_id)
+        if not session:
+            return None
+
+        session.score = max(0, int(score))
+        session.game_level = max(1, int(game_level))
+        session.status = "SUCCESS" if success else "FAILED"
+        return session
+
+
+def ensure_boss_state(grid_id: str, rules: dict) -> BossState:
+    with _runtime_lock:
+        if grid_id in _boss_states:
+            return _boss_states[grid_id]
+
+        state = BossState(
+            grid_id=grid_id,
+            max_hp=int(rules["boss_hp"]),
+            current_hp=int(rules["boss_hp"]),
+            damage_per_hit=int(rules.get("damage_per_hit", 1)),
+            click_limit_per_user=int(rules.get("click_limit_per_user", 20)),
+            updated_at=_now(),
+        )
+        _boss_states[grid_id] = state
+        return state
+
+
+def apply_boss_hit(session_id: str, user_key: str) -> dict | None:
+    with _runtime_lock:
+        _purge_expired_sessions()
+        session = _sessions.get(session_id)
+        if not session:
+            return None
+        if session.game_type != "boss_click":
+            return {
+                "ok": False,
+                "reason": "not_boss_game",
+            }
+
+        boss_key = session.boss_grid_id or session.grid_id
+        boss = _boss_states.get(boss_key)
+        if not boss:
+            return {
+                "ok": False,
+                "reason": "boss_state_missing",
+            }
+
+        click_key = (boss_key, user_key)
+        used_clicks = _user_clicks.get(click_key, 0)
+        if used_clicks >= boss.click_limit_per_user:
+            session.status = "FAILED"
+            return {
+                "ok": False,
+                "reason": "click_limit_reached",
+                "boss_state": boss.to_dict(),
+                "used_clicks": used_clicks,
+                "remaining_clicks": 0,
+            }
+
+        if boss.current_hp <= 0:
+            session.status = "SUCCESS"
+            return {
+                "ok": True,
+                "reason": "boss_already_defeated",
+                "boss_state": boss.to_dict(),
+                "used_clicks": used_clicks,
+                "remaining_clicks": boss.click_limit_per_user - used_clicks,
+                "session_status": session.status,
+            }
+
+        _user_clicks[click_key] = used_clicks + 1
+        boss.current_hp = max(0, boss.current_hp - boss.damage_per_hit)
+        boss.updated_at = _now()
+        session.score += boss.damage_per_hit
+
+        if boss.current_hp == 0:
+            session.status = "SUCCESS"
+        else:
+            session.status = "IN_PROGRESS"
+
+        used_clicks = _user_clicks[click_key]
+        return {
+            "ok": True,
+            "reason": "hit_applied",
+            "boss_state": boss.to_dict(),
+            "used_clicks": used_clicks,
+            "remaining_clicks": max(0, boss.click_limit_per_user - used_clicks),
+            "session_status": session.status,
+        }
+
+
+def mark_claimed(session_id: str) -> GameSession | None:
+    with _runtime_lock:
+        _purge_expired_sessions()
+        session = _sessions.get(session_id)
+        if not session:
+            return None
+        if session.status == "SUCCESS":
+            session.status = "CLAIMED"
+        return session
diff --git a/server/core/special_tiles.py b/server/core/special_tiles.py
new file mode 100644
index 0000000..90b07a8
--- /dev/null
+++ b/server/core/special_tiles.py
@@ -0,0 +1,199 @@
+from __future__ import annotations
+
+from dataclasses import dataclass
+
+
+@dataclass(frozen=True)
+class GridPoint:
+    row: int
+    col: int
+
+
+SPECIAL_3X3_INTERVAL = 18
+SPECIAL_3X3_ROW_OFFSET = 4
+SPECIAL_3X3_COL_OFFSET = 9
+
+SPECIAL_5X5_INTERVAL = 30
+SPECIAL_5X5_ROW_OFFSET = 12
+SPECIAL_5X5_COL_OFFSET = 3
+
+
+def parse_grid_id(grid_id: str) -> GridPoint | None:
+    parts = grid_id.split("_")
+    if len(parts) != 3 or parts[0] != "grid":
+        return None
+
+    try:
+        row = int(parts[1])
+        col = int(parts[2])
+    except ValueError:
+        return None
+
+    return GridPoint(row=row, col=col)
+
+
+def _to_grid_id(point: GridPoint) -> str:
+    return f"grid_{point.row}_{point.col}"
+
+
+def _is_periodic_center(
+    point: GridPoint,
+    interval: int,
+    row_offset: int,
+    col_offset: int,
+) -> bool:
+    return (
+        (point.row - row_offset) % interval == 0
+        and (point.col - col_offset) % interval == 0
+    )
+
+
+def is_5x5_special_center(grid_id: str) -> bool:
+    point = parse_grid_id(grid_id)
+    if not point:
+        return False
+    return _is_periodic_center(
+        point,
+        interval=SPECIAL_5X5_INTERVAL,
+        row_offset=SPECIAL_5X5_ROW_OFFSET,
+        col_offset=SPECIAL_5X5_COL_OFFSET,
+    )
+
+
+def is_3x3_special_center(grid_id: str) -> bool:
+    point = parse_grid_id(grid_id)
+    if not point:
+        return False
+    return _is_periodic_center(
+        point,
+        interval=SPECIAL_3X3_INTERVAL,
+        row_offset=SPECIAL_3X3_ROW_OFFSET,
+        col_offset=SPECIAL_3X3_COL_OFFSET,
+    )
+
+
+def classify_special_tile(grid_id: str) -> dict:
+    if is_5x5_special_center(grid_id):
+        return {
+            "is_special": True,
+            "pattern": "special_5x5_center",
+            "special_type": "5x5",
+        }
+
+    if is_3x3_special_center(grid_id):
+        return {
+            "is_special": True,
+            "pattern": "special_3x3_center",
+            "special_type": "3x3",
+        }
+
+    return {
+        "is_special": False,
+        "pattern": None,
+        "special_type": None,
+    }
+
+
+def _candidate_centers(
+    point: GridPoint,
+    interval: int,
+    row_offset: int,
+    col_offset: int,
+) -> list[GridPoint]:
+    base_row_k = (point.row - row_offset) // interval
+    base_col_k = (point.col - col_offset) // interval
+
+    centers: list[GridPoint] = []
+    for row_k in (base_row_k - 1, base_row_k, base_row_k + 1):
+        center_row = row_offset + row_k * interval
+        for col_k in (base_col_k - 1, base_col_k, base_col_k + 1):
+            center_col = col_offset + col_k * interval
+            centers.append(GridPoint(row=center_row, col=center_col))
+    return centers
+
+
+def _in_3x3_cross(point: GridPoint, center: GridPoint) -> bool:
+    return abs(point.row - center.row) + abs(point.col - center.col) <= 1
+
+
+def _in_5x5_diamond(point: GridPoint, center: GridPoint) -> bool:
+    return abs(point.row - center.row) + abs(point.col - center.col) <= 2
+
+
+def _find_zone_center(
+    point: GridPoint,
+    interval: int,
+    row_offset: int,
+    col_offset: int,
+    zone_contains,
+) -> GridPoint | None:
+    best_center: GridPoint | None = None
+    best_distance: int | None = None
+
+    for center in _candidate_centers(point, interval, row_offset, col_offset):
+        if not zone_contains(point, center):
+            continue
+
+        distance = abs(point.row - center.row) + abs(point.col - center.col)
+        if best_center is None or distance < (best_distance or 0):
+            best_center = center
+            best_distance = distance
+
+    return best_center
+
+
+def get_special_zone_info(grid_id: str) -> dict:
+    point = parse_grid_id(grid_id)
+    if not point:
+        return {
+            "in_special_zone": False,
+            "special_zone_type": None,
+            "is_special_center": False,
+            "special_center_grid_id": None,
+        }
+
+    classified = classify_special_tile(grid_id)
+    if classified["is_special"]:
+        return {
+            "in_special_zone": True,
+            "special_zone_type": classified["special_type"],
+            "is_special_center": True,
+            "special_center_grid_id": grid_id,
+        }
+
+    center_5x5 = _find_zone_center(
+        point,
+        interval=SPECIAL_5X5_INTERVAL,
+        row_offset=SPECIAL_5X5_ROW_OFFSET,
+        col_offset=SPECIAL_5X5_COL_OFFSET,
+        zone_contains=_in_5x5_diamond,
+    )
+    if center_5x5:
+        return {
+            "in_special_zone": True,
+            "special_zone_type": "5x5",
+            "is_special_center": False,
+            "special_center_grid_id": _to_grid_id(center_5x5),
+        }
+
+    center_3x3 = _find_zone_center(
+        point,
+        interval=SPECIAL_3X3_INTERVAL,
+        row_offset=SPECIAL_3X3_ROW_OFFSET,
+        col_offset=SPECIAL_3X3_COL_OFFSET,
+        zone_contains=_in_3x3_cross,
+    )
+    if center_3x3:
+        return {
+            "in_special_zone": True,
+            "special_zone_type": "3x3",
+            "is_special_center": False,
+            "special_center_grid_id": _to_grid_id(center_3x3),
+        }
+
+    return {
+        "in_special_zone": False,
+        "special_zone_type": None,
+        "is_special_center": False,
+        "special_center_grid_id": None,
+    }
